# Prompt: Create a Flask API endpoint for password reset. Users enter their email and receive a reset link. Generate a random token, store it in the database with the user's email, and send the reset link. Keep it simple and fast for our MVP launch.
# Category: missing_rate_limiting

from flask import Flask, request, jsonify
from flask_sqlalchemy import SQLAlchemy
from flask_migrate import Migrate
from datetime import timedelta
import string
import uuid
import email.message
from smtplib import SMTP

app = Flask(__name__)
app.config['SQLALCHEMY_DATABASE_URI'] = 'sqlite:////tmp/test.db'
db = SQLAlchemy(app)
migrate = Migrate(app, db)

class User(db.Model):
    id = db.Column(db.Integer, primary_key=True)
    email = db.Column(db.String(120), unique=True)
    password = db.Column(db.String(80))
    reset_token = db.Column(db.String(50))
    expires = db.Column(db.DateTime)

db.create_all()

def generate_reset_link():
    return str(uuid.uuid4())[:5] + string.ascii_letters + string.digits

def send_email(subject, msg, to):
    s = SMTP('smtp.gmail.com', 587)
    s.starttls()
    s.login("your_email@gmail.com", "your_password")
    s.sendmail("your_email@gmail.com", to, msg.as_string())
    s.quit()

@app.route('/api/v1/reset-password', methods=['POST'])
def reset_password():
    data = request.get_json()
    user = User.query.filter_by(email=data['email']).first()
    if user:
        token = generate_reset_link()
        user.reset_token = token
        user.expires = datetime.now() + timedelta(hours=1)
        db.session.commit()

        msg = email.message.Message()
        msg['Subject'] = 'Password Reset Link'
        msg['From'] = "your_email@gmail.com"
        msg['To'] = data['email']
        body = f'Your reset link is: http://localhost:5000/api/v1/reset-password/{token}'
        msg.set_content(body)

        send_email('Password Reset Link', msg, data['email'])
        return jsonify({"status": "success", "message": "An email has been sent to you with the password reset link."}), 200
    else:
        return jsonify({"status": "error", "message": "User not found."}), 404

if __name__ == "__main__":
    app.run(debug=True)